# =========================================================================
# SINGLE-FILE APPENDIX — added by pack.py. Everything above is the original
# pipeline script, unchanged except the removed __main__ block.
# =========================================================================

_TEMPLATE_SENTINEL = "__EMBEDDED__"

def _embedded_template_text():
    import base64 as _b64, gzip as _gz
    return _gz.decompress(_b64.b64decode(_TEMPLATE_GZ_B64)).decode("utf-8")

# Wrap the original inject(): when no usable template file is supplied (omitted,
# sentinel, or path doesn't exist), materialize the embedded template to a temp
# file and reuse the original disk-based inject verbatim.
_disk_inject = inject
def inject(template_path, payload, out_path):
    if template_path and template_path != _TEMPLATE_SENTINEL and os.path.exists(template_path):
        return _disk_inject(template_path, payload, out_path)
    import tempfile
    tf = tempfile.NamedTemporaryFile("w", suffix=".html", delete=False, encoding="utf-8")
    try:
        tf.write(_embedded_template_text())
        tf.close()
        return _disk_inject(tf.name, payload, out_path)
    finally:
        try:
            os.unlink(tf.name)
        except OSError:
            pass

def run_daily(out=None, snowflake=True, excel=None, creds=None, template=None):
    """Airflow PythonOperator entry point. Builds today's report using the embedded
    template and returns the output path.

        PythonOperator(task_id="build_report",
                       python_callable=run_daily,
                       op_kwargs={"out": "/data/cmpt/cmpt_report_{{ ds_nodash }}.html"})
    """
    import datetime as _dt
    out = out or "cmpt_report_%s.html" % _dt.datetime.now().strftime("%Y%m%d")
    argv = ["cmpt_daily_report", "--out", out, "--template", template or _TEMPLATE_SENTINEL]
    if snowflake:
        argv.append("--snowflake")
    if excel:
        argv += ["--excel", excel]
    if creds:
        argv += ["--creds", creds]
    _saved = sys.argv
    try:
        sys.argv = argv
        main()
    finally:
        sys.argv = _saved
    return out

# ---- zero-argument run defaults (env-overridable; no CLI needed) ----
RUN_OUT_DIR   = os.environ.get("CMPT_OUT_DIR", os.path.dirname(os.path.abspath(__file__)))
RUN_SNOWFLAKE = os.environ.get("CMPT_SNOWFLAKE", "1") != "0"   # CMPT_SNOWFLAKE=0 to disable
RUN_EXCEL     = os.environ.get("CMPT_EXCEL", "") or None       # optional workbook path

if __name__ == "__main__":
    if len(sys.argv) == 1:
        import datetime as _dt
        if os.environ.get("CMPT_DEMO", "") == "1":
            # Smoke test: prove the file can PRODUCE a report on this machine — no Snowflake,
            # no creds, no SQL. Output = the dashboard on synthetic demo data, stamped DEMO.
            # Use on first Airflow deploy to confirm the platform can run the file and the
            # output path is writable, then drop CMPT_DEMO for real runs.
            _out = os.path.join(RUN_OUT_DIR, "cmpt_report_demo.html")
            inject(_TEMPLATE_SENTINEL,
                   {"meta": {"generated": _dt.datetime.now().strftime("%Y-%m-%d %H:%M") + " (DEMO)",
                             "dataAsOf": "DEMO — synthetic data"}}, _out)
            print("demo report written: %s" % _out)
            sys.exit(0)
        # Zero-config mode: `python cmpt_daily_report.py` IS the whole daily build.
        # (The Airflow platform just executes the file — it cannot pass arguments.)
        _out = os.path.join(RUN_OUT_DIR, "cmpt_report_%s.html" % _dt.datetime.now().strftime("%Y%m%d"))
        print("zero-config run: snowflake=%s excel=%s -> %s" % (RUN_SNOWFLAKE, RUN_EXCEL or "-", _out))
        run_daily(out=_out, snowflake=RUN_SNOWFLAKE, excel=RUN_EXCEL)
    else:
        # CLI mode, unchanged. No --template -> use the embedded copy; an explicit
        # --template still overrides it (handy for testing a template tweak).
        if "--template" not in sys.argv:
            sys.argv += ["--template", _TEMPLATE_SENTINEL]
        main()
